mapper.select:
select * from tipo_documento
where tido_estado = true
order by tido_nombre;

select * from tipo_documento
where tido_nombre ilike #{c} or tido_descripcion ilike #{c}
order by tido_nombre;

select td.tido_id, td.tido_nombre, td.tido_estado, td.tido_descripcion, 
td.tido_metadata, td.tido_privacidad, c.cate_id, c.cate_nombre 
from tipo_documento as td, categoria as c ${c}
order by td.tido_nombre ASC;

mapper.update:
UPDATE tipo_documento
SET  tido_nombre = #{nombre}, tido_estado = #{estado}, tido_descripcion = #{descripcion}, 
tido_metadata = #{metadata}, tido_privacidad = #{privacidad}, cate_id = #{cateId}
WHERE tido_id = #{id}

mapper.select:
select * from sub_tipo
where tido_id =#{tidoId} and estado = true or nombre ilike #{c}
order by nombre;

mapper.update:
UPDATE sub_tipo
set nombre = #{nombre}
WHERE  id = #{id}

mapper.delete:

UPDATE sub_tipo
set estado = false
where id = #{id}
